// Optimized with swapped flag
function bubbleSortClassic(arr) {
  let swapped;
  do {
    swapped = false;
    for (let i = 0; i < arr.length - 1; i++) {
      if (arr[i] > arr[i + 1]) {
        [arr[i], arr[i + 1]] = [arr[i + 1], arr[i]];

        swapped = true;
      }
    }
  } while (swapped);
  return arr;
}

// Recursive with generator for visualization
function* bubbleSortRecursive(arr) {
  const copy = [...arr];
  if (copy.length <= 1) return copy;
  yield* bubbleSortRecursive(copy.slice(0, -1));
  // Bubble last element
  for (let i = 0; i < copy.length - 1; i++) {
    if (copy[i] > copy[i + 1]) [copy[i], copy[i + 1]] = [copy[i + 1], copy[i]];
    yield [...copy];
  }
  return copy;
}
